text:
Select two Iowa legislators to see how often they voted the same way. The vote agreement rate is the share of roll call votes where both cast the same vote (Yea or Nay). Absences and Not Voting are excluded.

pairMap = {
  const m = new Map();
  for (const p of pair_data) {
    m.set(`${p.people_id_a}_${p.people_id_b}`, p);
    m.set(`${p.people_id_b}_${p.people_id_a}`, p);
  }
  return m;
}

// Senators first (alphabetical), then Representatives
all_sorted = [
  ...legislators.filter(d =&gt; d.role === "Sen").sort((a, b) =&gt; a.name.localeCompare(b.name)),
  ...legislators.filter(d =&gt; d.role === "Rep").sort((a, b) =&gt; a.name.localeCompare(b.name))
]

viewof leg_a = Inputs.select(all_sorted, {
  label: "Legislator A",
  format: d =&gt; `${d.name} (${d.party}-${d.district})`,
  width: 360
})

viewof leg_b = Inputs.select(all_sorted, {
  label: "Legislator B",
  format: d =&gt; `${d.name} (${d.party}-${d.district})`,
  width: 360
})

result = {
  if (!leg_a || !leg_b) return { type: "none" };
  if (leg_a.people_id === leg_b.people_id) return { type: "same" };
  const p = pairMap.get(`${leg_a.people_id}_${leg_b.people_id}`);
  return p ? { type: "found", ...p } : { type: "insufficient" };
}

scoreColor = result.type === "found"
  ? (result.similarity &gt;= 0.8 ? "#1565C0"
   : result.similarity &gt;= 0.5 ? "#E65100"
   : "#B71C1C")
  : "#555"

html`&lt;div style="margin-top: 2rem; text-align: center; font-family: sans-serif;"&gt;
  ${result.type === "same"
    ? html`&lt;p style="color: #888; margin-top: 1rem;"&gt;Select two &lt;em&gt;different&lt;/em&gt; legislators.&lt;/p&gt;`

    : result.type === "insufficient"
    ? html`&lt;div style="max-width: 520px; margin: 1.5rem auto; padding: 1rem 1.5rem;
                       background: #f9f9f9; border-radius: 6px; color: #555; font-size: 0.95rem;"&gt;
        &lt;strong&gt;Not enough shared votes&lt;/strong&gt;&lt;br&gt;&lt;br&gt;
        These two legislators voted together on fewer than 20 roll calls, so a reliable
        similarity score cannot be computed. They may be in different chambers or have
        little overlap in the bills they voted on.
      &lt;/div&gt;`

    : result.type === "found"
    ? html`&lt;div&gt;
        &lt;div style="margin-bottom: 0.75rem; font-size: 1rem;"&gt;
          &lt;a href="${leg_a.filename}.html" style="font-weight: 600;"&gt;${leg_a.name}&lt;/a&gt;
          &lt;span style="color: #aaa; margin: 0 0.6rem;"&gt;vs.&lt;/span&gt;
          &lt;a href="${leg_b.filename}.html" style="font-weight: 600;"&gt;${leg_b.name}&lt;/a&gt;
        &lt;/div&gt;
        &lt;div style="font-size: 5rem; font-weight: 800; color: ${scoreColor}; line-height: 1.1; margin: 0.25rem 0;"&gt;
          ${(result.similarity * 100).toFixed(1)}%
        &lt;/div&gt;
        &lt;div style="color: #888; font-size: 0.9rem; margin-bottom: 1.75rem;"&gt;vote agreement rate&lt;/div&gt;
        &lt;table style="margin: auto; border-collapse: collapse; font-size: 0.95rem; min-width: 280px;"&gt;
          &lt;tbody&gt;
            &lt;tr style="border-bottom: 1px solid #eee;"&gt;
              &lt;td style="padding: 8px 20px; color: #555; text-align: left;"&gt;Roll calls both voted on&lt;/td&gt;
              &lt;td style="padding: 8px 20px; font-weight: 600; text-align: right;"&gt;${result.n_shared.toLocaleString()}&lt;/td&gt;
            &lt;/tr&gt;
            &lt;tr style="border-bottom: 1px solid #eee;"&gt;
              &lt;td style="padding: 8px 20px; color: #555; text-align: left;"&gt;Voted the same&lt;/td&gt;
              &lt;td style="padding: 8px 20px; font-weight: 600; text-align: right;"&gt;${result.n_agree.toLocaleString()}&lt;/td&gt;
            &lt;/tr&gt;
            &lt;tr&gt;
              &lt;td style="padding: 8px 20px; color: #555; text-align: left;"&gt;Voted differently&lt;/td&gt;
              &lt;td style="padding: 8px 20px; font-weight: 600; text-align: right;"&gt;${result.n_disagree.toLocaleString()}&lt;/td&gt;
            &lt;/tr&gt;
          &lt;/tbody&gt;
        &lt;/table&gt;
        &lt;div style="margin-top: 1.75rem; font-size: 0.8rem; color: #bbb;"&gt;
          Based on 91st General Assembly floor votes &bull; Minimum 20 shared votes required
        &lt;/div&gt;
      &lt;/div&gt;`

    : ""
  }
&lt;/div&gt;`
